-- Phase 3: Vocabulary Building
-- Topic: Essential Vocabulary (150 questions)
-- Level: beginner (A1)
-- Distribution: 60 easy, 60 medium, 30 hard
-- Subtopics: Daily Objects (30Q), Actions & Verbs (30Q), Emotions & Feelings (30Q), Time & Frequency (30Q), Places & Locations (30Q)

INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES

-- Subtopic 1: Daily Objects (30Q) - 12 easy, 12 medium, 6 hard
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to write on paper?', '["Pen", "Spoon", "Plate", "Cup"]', 0, 'A pen is used for writing on paper. Spoons are for eating, plates hold food, and cups hold drinks.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you keep your clothes?', '["Wardrobe", "Refrigerator", "Oven", "Sink"]', 0, 'A wardrobe (or closet) is used to store clothes. Refrigerators keep food cold, ovens cook food, and sinks are for washing.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you sit on?', '["Chair", "Wall", "Ceiling", "Floor"]', 0, 'A chair is furniture designed for sitting. While you can sit on the floor, a chair is the primary sitting furniture.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to cut paper?', '["Scissors", "Hammer", "Screwdriver", "Wrench"]', 0, 'Scissors are designed to cut paper and fabric. Other tools are for construction or repair work.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What tells you the time?', '["Clock", "Mirror", "Picture", "Lamp"]', 0, 'A clock displays the current time. Mirrors reflect images, pictures are decorations, and lamps provide light.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you sleep on?', '["Bed", "Table", "Desk", "Shelf"]', 0, 'A bed is furniture designed for sleeping. Tables and desks are for working or eating, shelves are for storage.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to brush your teeth?', '["Toothbrush", "Comb", "Spoon", "Fork"]', 0, 'A toothbrush is designed for cleaning teeth. Combs are for hair, spoons and forks are eating utensils.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you wear on your feet?', '["Shoes", "Gloves", "Hat", "Scarf"]', 0, 'Shoes are worn on feet for protection and comfort. Gloves are for hands, hats for head, scarves around neck.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to unlock a door?', '["Key", "Button", "Switch", "Knob"]', 0, 'A key is used to lock and unlock doors. Buttons, switches, and knobs serve different purposes.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you drink water from?', '["Glass", "Plate", "Bowl", "Pan"]', 0, 'A glass (or cup) is used for drinking liquids. Plates are for solid food, bowls for soups, pans for cooking.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to see in the dark?', '["Flashlight", "Book", "Pillow", "Blanket"]', 0, 'A flashlight (or torch) provides light in dark places. Books are for reading, pillows and blankets are for sleeping.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to dry yourself after a bath?', '["Towel", "Napkin", "Tissue", "Cloth"]', 0, 'A towel is specifically designed for drying the body after bathing. Napkins are for meals, tissues for nose, cloths for cleaning.', 'easy'),

('foundation', 'essential-vocabulary', 'beginner', 'What kitchen item do you use to boil water?', '["Kettle", "Colander", "Grater", "Peeler"]', 1, 'A kettle is designed to boil water quickly. Colanders drain liquids, graters shred food, peelers remove skin from vegetables.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to clean the floor?', '["Broom", "Duster", "Sponge", "Towel"]', 0, 'A broom sweeps floors by gathering dirt. Dusters clean surfaces, sponges wash dishes, towels dry things.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What office item holds papers together?', '["Stapler", "Eraser", "Ruler", "Sharpener"]', 0, 'A stapler uses metal staples to bind papers together. Erasers remove pencil marks, rulers measure length, sharpeners make pencils sharp.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to measure your weight?', '["Scale", "Thermometer", "Barometer", "Compass"]', 0, 'A scale (or weighing machine) measures body weight. Thermometers measure temperature, barometers measure air pressure, compasses show direction.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What furniture item stores books?', '["Bookshelf", "Cupboard", "Drawer", "Cabinet"]', 0, 'A bookshelf is designed specifically for displaying and storing books. Cupboards store dishes, drawers hold small items, cabinets are general storage.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to water plants?', '["Watering can", "Bucket", "Mug", "Jug"]', 0, 'A watering can has a spout designed for gentle watering of plants. Buckets, mugs, and jugs can hold water but aren''t designed for plant watering.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to open a bottle?', '["Bottle opener", "Can opener", "Corkscrew", "Knife"]', 0, 'A bottle opener removes metal caps from bottles. Can openers open cans, corkscrews remove corks, knives cut things.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What electronic device makes clothes clean?', '["Washing machine", "Dryer", "Iron", "Vacuum cleaner"]', 0, 'A washing machine cleans clothes with water and detergent. Dryers remove moisture, irons remove wrinkles, vacuum cleaners clean floors.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to remove dust from furniture?', '["Duster", "Broom", "Mop", "Vacuum"]', 0, 'A duster is designed to remove dust from surfaces and furniture. Brooms sweep floors, mops clean wet surfaces, vacuums suck up dirt.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What kitchen appliance keeps food cold?', '["Refrigerator", "Oven", "Microwave", "Toaster"]', 0, 'A refrigerator keeps food cold to preserve it. Ovens bake food, microwaves heat food quickly, toasters brown bread.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to protect yourself from rain?', '["Umbrella", "Raincoat", "Hat", "Jacket"]', 0, 'An umbrella provides overhead protection from rain. A raincoat also protects from rain, but umbrella is the most common answer for this question.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you use to sew clothes?', '["Needle", "Pin", "Hook", "Clip"]', 0, 'A needle with thread is used for sewing fabric together. Pins temporarily hold fabric, hooks and clips fasten things differently.', 'medium'),

('foundation', 'essential-vocabulary', 'beginner', 'What kitchen utensil is used to strain pasta?', '["Colander", "Strainer", "Sieve", "Filter"]', 0, 'A colander is a bowl-shaped kitchen utensil with holes for draining water from pasta or vegetables. All options are similar, but colander is most specific for pasta.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What item helps you find north, south, east, and west?', '["Compass", "Map", "GPS", "Clock"]', 0, 'A compass uses a magnetic needle to show cardinal directions. Maps show locations, GPS gives coordinates, clocks show time.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What tool do carpenters use to make wood smooth?', '["Sandpaper", "Hammer", "Saw", "Drill"]', 0, 'Sandpaper smooths rough wood surfaces through abrasion. Hammers drive nails, saws cut wood, drills make holes.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What laboratory equipment measures small amounts of liquid?', '["Pipette", "Beaker", "Flask", "Cylinder"]', 0, 'A pipette precisely measures and transfers small liquid volumes. Beakers and flasks hold liquids, cylinders measure larger volumes.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What household item removes wrinkles from clothes?', '["Iron", "Steamer", "Press", "Roller"]', 0, 'An iron uses heat and pressure to remove wrinkles from fabric. A steamer also works, but iron is the traditional and most common tool.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What do gardeners use to dig soil?', '["Spade", "Rake", "Hoe", "Trowel"]', 0, 'A spade is a digging tool with a sharp blade for turning soil. Rakes gather leaves, hoes break soil, trowels are for small digging.', 'hard'),

-- Subtopic 2: Actions & Verbs (30Q) - 12 easy, 12 medium, 6 hard
('foundation', 'essential-vocabulary', 'beginner', 'What do you do with your eyes?', '["See", "Hear", "Smell", "Taste"]', 0, 'Eyes are used to see (or look at) things. Ears hear, noses smell, tongues taste.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do with food?', '["Eat", "Drink", "Sleep", "Walk"]', 0, 'We eat solid food. We drink liquids, sleep for rest, and walk to move around.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do when you are tired?', '["Sleep", "Run", "Jump", "Sing"]', 0, 'When tired, we sleep to rest and recharge. Running, jumping, and singing require energy.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do with a book?', '["Read", "Write", "Draw", "Cut"]', 0, 'We read books to gain information or enjoyment. We write in notebooks, draw on paper, cut with scissors.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do with your ears?', '["Hear", "See", "Smell", "Touch"]', 0, 'Ears are used to hear (or listen to) sounds. Eyes see, noses smell, hands touch.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do when you are happy?', '["Smile", "Cry", "Frown", "Yawn"]', 0, 'When happy, we smile. We cry when sad, frown when upset, yawn when tired or bored.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do with water?', '["Drink", "Eat", "Read", "Write"]', 0, 'We drink water to stay hydrated. We eat food, read books, and write with pens.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do with your legs?', '["Walk", "Think", "Speak", "See"]', 0, 'We use legs to walk or run. We think with our brain, speak with our mouth, see with our eyes.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do with a pen?', '["Write", "Read", "Listen", "Watch"]', 0, 'We write with a pen to record information. We read books, listen to sounds, watch television.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do when you meet someone?', '["Greet", "Leave", "Hide", "Sleep"]', 0, 'When we meet someone, we greet them by saying hello. Leaving, hiding, and sleeping are opposite actions.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do with a ball?', '["Throw", "Read", "Write", "Draw"]', 0, 'We throw (or kick) a ball in games and sports. We read books, write letters, and draw pictures.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do in the morning?', '["Wake up", "Sleep", "Dream", "Snore"]', 0, 'In the morning, we wake up from sleep. We sleep at night, dream while sleeping, some people snore.', 'easy'),

('foundation', 'essential-vocabulary', 'beginner', 'What do you do to make yourself clean?', '["Bathe", "Rest", "Work", "Play"]', 0, 'We bathe (or shower) to clean our body. Rest is for relaxation, work is for tasks, play is for fun.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do when something is funny?', '["Laugh", "Cry", "Shout", "Whisper"]', 0, 'When something is funny, we laugh. We cry when sad, shout when angry, whisper when speaking quietly.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to remember information?', '["Memorize", "Forget", "Ignore", "Delete"]', 0, 'We memorize (or learn) information to remember it. Forget, ignore, and delete are opposite actions.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to find something hidden?', '["Search", "Lose", "Hide", "Forget"]', 0, 'We search (or look for) something that is hidden or lost. Lose, hide, and forget make things harder to find.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do when you want to know the answer?', '["Ask", "Ignore", "Forget", "Sleep"]', 0, 'When we want to know something, we ask a question. Ignoring, forgetting, and sleeping won''t help us learn.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do with a gift?', '["Receive", "Steal", "Lose", "Break"]', 0, 'We receive (or accept) a gift when someone gives it to us. Steal means take illegally, lose and break are negative.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to help someone in danger?', '["Rescue", "Harm", "Ignore", "Watch"]', 0, 'We rescue (or save) someone who is in danger. Harm means hurt, ignore means not care, watch means just observe.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do when you want to go faster?', '["Hurry", "Wait", "Stop", "Rest"]', 0, 'When we want to go faster, we hurry (or rush). Wait, stop, and rest slow us down or make us stay still.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to make food ready to eat?', '["Cook", "Freeze", "Store", "Throw"]', 0, 'We cook food to make it ready to eat. Freeze preserves food, store keeps it safe, throw means discard.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do when you want to know more?', '["Learn", "Ignore", "Forget", "Quit"]', 0, 'When we want to know more, we learn (or study). Ignore, forget, and quit prevent learning.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to make something beautiful?', '["Decorate', 'Destroy", "Break", "Damage"]', 0, 'We decorate things to make them beautiful or attractive. Destroy, break, and damage make things worse.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do when you want to keep a promise?', '["Fulfill", "Break", "Forget", "Ignore"]', 0, 'We fulfill (or keep) a promise when we do what we said. Break, forget, and ignore mean not keeping a promise.', 'medium'),

('foundation', 'essential-vocabulary', 'beginner', 'What do you do to make something last longer?', '["Preserve", "Destroy", "Waste", "Ruin"]', 0, 'We preserve (or maintain) things to make them last longer. Destroy, waste, and ruin make things deteriorate.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to show respect to elders?', '["Honour", "Disrespect", "Insult", "Mock"]', 0, 'We honour (or respect) elders by treating them with dignity. Disrespect, insult, and mock are opposite behaviors.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to make a decision between options?', '["Choose", "Avoid", "Reject", "Refuse"]', 0, 'We choose (or select) when making a decision. Avoid, reject, and refuse mean not selecting something.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to make something better?', '["Improve", "Worsen", "Damage", "Spoil"]', 0, 'We improve (or enhance) something to make it better. Worsen, damage, and spoil make things worse.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to show you agree with someone?', '["Approve", "Oppose", "Reject", "Deny"]', 0, 'We approve (or agree) to show we support something. Oppose, reject, and deny show disagreement.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you do to make something work properly?', '["Repair", "Break", "Damage", "Destroy"]', 0, 'We repair (or fix) something to make it work properly. Break, damage, and destroy make things stop working.', 'hard'),

-- Subtopic 3: Emotions & Feelings (30Q) - 12 easy, 12 medium, 6 hard
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you get a gift?', '["Happy", "Sad", "Angry", "Bored"]', 0, 'We feel happy when we receive gifts. Sad, angry, and bored are negative emotions.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when someone hurts you?', '["Sad", "Happy", "Excited", "Proud"]', 0, 'We feel sad (or hurt) when someone causes us pain. Happy, excited, and proud are positive emotions.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you win a game?', '["Proud", "Ashamed", "Guilty", "Sorry"]', 0, 'We feel proud when we win or achieve something. Ashamed, guilty, and sorry are negative emotions.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you are alone for a long time?', '["Lonely", "Crowded", "Busy", "Popular"]', 0, 'We feel lonely when we are alone and miss company. Crowded, busy, and popular involve being with others.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when something bad might happen?', '["Scared", "Brave", "Confident", "Safe"]', 0, 'We feel scared (or afraid) when in danger. Brave, confident, and safe are opposite feelings.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you have nothing to do?', '["Bored", "Excited", "Busy", "Interested"]', 0, 'We feel bored when we have nothing interesting to do. Excited, busy, and interested are opposite states.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you do something wrong?', '["Guilty", "Proud", "Happy", "Excited"]', 0, 'We feel guilty when we do something wrong or bad. Proud, happy, and excited are positive emotions.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you see a scary movie?', '["Frightened", "Relaxed", "Calm", "Peaceful"]', 0, 'We feel frightened (or scared) when watching scary content. Relaxed, calm, and peaceful are opposite feelings.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you wait for good news?', '["Excited", "Bored", "Tired", "Sleepy"]', 0, 'We feel excited when anticipating something good. Bored, tired, and sleepy are low-energy states.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when someone lies to you?', '["Angry", "Happy", "Proud", "Grateful"]', 0, 'We feel angry (or upset) when someone lies to us. Happy, proud, and grateful are positive emotions.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you help someone?', '["Good", "Bad", "Guilty", "Ashamed"]', 0, 'We feel good (or satisfied) when we help others. Bad, guilty, and ashamed are negative feelings.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you lose something important?', '["Upset", "Happy", "Excited", "Joyful"]', 0, 'We feel upset (or sad) when we lose something valuable. Happy, excited, and joyful are positive emotions.', 'easy'),

('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you can''t understand something?', '["Confused", "Clear", "Certain", "Sure"]', 0, 'We feel confused when something is unclear or difficult to understand. Clear, certain, and sure indicate understanding.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you work very hard?', '["Tired", "Energetic", "Fresh", "Lively"]', 0, 'We feel tired (or exhausted) after working hard. Energetic, fresh, and lively indicate having energy.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when someone praises you?', '["Pleased", "Insulted", "Offended", "Hurt"]', 0, 'We feel pleased (or happy) when receiving praise. Insulted, offended, and hurt are negative reactions.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you can''t decide what to do?', '["Uncertain", "Confident", "Sure", "Decided"]', 0, 'We feel uncertain (or doubtful) when we can''t make a decision. Confident, sure, and decided are opposite states.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when someone ignores you?', '["Hurt", "Valued", "Important", "Respected"]', 0, 'We feel hurt (or neglected) when ignored. Valued, important, and respected are opposite feelings.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you achieve your goal?', '["Satisfied", "Disappointed", "Frustrated", "Defeated"]', 0, 'We feel satisfied (or fulfilled) when achieving goals. Disappointed, frustrated, and defeated are negative emotions.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you make a mistake?', '["Embarrassed", "Proud", "Confident", "Bold"]', 0, 'We feel embarrassed (or ashamed) when making mistakes. Proud, confident, and bold are opposite feelings.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you see someone suffering?', '["Sympathetic", "Cruel", "Harsh", "Mean"]', 0, 'We feel sympathetic (or compassionate) toward those suffering. Cruel, harsh, and mean are opposite attitudes.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you can''t do what you want?', '["Frustrated", "Pleased", "Satisfied", "Content"]', 0, 'We feel frustrated (or annoyed) when restricted. Pleased, satisfied, and content are positive emotions.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you meet someone new?', '["Nervous", "Comfortable", "Relaxed", "Familiar"]', 0, 'We often feel nervous (or anxious) meeting new people. Comfortable, relaxed, and familiar come with knowing someone.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you remember something sad?', '["Nostalgic", "Cheerful", "Merry", "Jolly"]', 0, 'We feel nostalgic (or melancholy) remembering sad times. Cheerful, merry, and jolly are happy emotions.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when someone breaks your trust?', '["Betrayed", "Trusting", "Loyal", "Faithful"]', 0, 'We feel betrayed (or deceived) when trust is broken. Trusting, loyal, and faithful are positive relationship feelings.', 'medium'),

('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you see something unfair?', '["Indignant", "Approving", "Agreeable", "Accepting"]', 0, 'We feel indignant (or outraged) witnessing injustice. Approving, agreeable, and accepting indicate acceptance of the situation.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you have too much work?', '["Overwhelmed", "Relaxed", "Comfortable", "Peaceful"]', 0, 'We feel overwhelmed (or stressed) with too much work. Relaxed, comfortable, and peaceful are opposite states.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when someone doubts your ability?', '["Offended", "Flattered", "Honored", "Complimented"]', 0, 'We feel offended (or insulted) when our abilities are doubted. Flattered, honored, and complimented are positive reactions.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you can''t express your thoughts?', '["Inarticulate", "Eloquent", "Fluent", "Articulate"]', 0, 'We feel inarticulate (or tongue-tied) when unable to express ourselves. Eloquent, fluent, and articulate describe good expression.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when everything goes wrong?', '["Discouraged", "Motivated", "Inspired", "Encouraged"]', 0, 'We feel discouraged (or demoralized) when facing continuous problems. Motivated, inspired, and encouraged are opposite feelings.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'How do you feel when you see others succeed?', '["Envious", "Generous", "Selfless", "Giving"]', 0, 'Some people feel envious (or jealous) of others'' success. Generous, selfless, and giving describe positive reactions to others'' fortune.', 'hard'),

-- Subtopic 4: Time & Frequency (30Q) - 12 easy, 12 medium, 6 hard
('foundation', 'essential-vocabulary', 'beginner', 'When does the sun rise?', '["Morning", "Afternoon", "Evening", "Night"]', 0, 'The sun rises in the morning. Afternoon is after noon, evening is before night, night is when it''s dark.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What comes after Monday?', '["Tuesday", "Sunday", "Saturday", "Friday"]', 0, 'Tuesday comes after Monday. The week order is: Monday, Tuesday, Wednesday, Thursday, Friday, Saturday, Sunday.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How many hours are in a day?', '["24", "12", "48", "60"]', 0, 'There are 24 hours in one complete day. 12 is half a day, 48 is two days, 60 is minutes in an hour.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What season comes after winter?', '["Spring", "Summer", "Autumn", "Rainy"]', 0, 'Spring comes after winter. The season order is: Winter, Spring, Summer, Autumn (Fall).', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How many days are in a week?', '["7", "5", "10", "14"]', 0, 'There are 7 days in one week: Monday through Sunday. 5 is weekdays, 10 and 14 are incorrect.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you call the middle of the day?', '["Noon", "Midnight", "Dawn", "Dusk"]', 0, 'Noon is 12:00 PM, the middle of the day. Midnight is 12:00 AM, dawn is early morning, dusk is early evening.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What month comes after March?', '["April", "May", "February", "June"]', 0, 'April comes after March. The month order is: January, February, March, April, May, June, etc.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How many minutes are in an hour?', '["60", "30", "100", "24"]', 0, 'There are 60 minutes in one hour. 30 is half an hour, 100 and 24 are incorrect.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What is the first month of the year?', '["January", "December", "March", "April"]', 0, 'January is the first month. December is the last (12th) month. March is 3rd, April is 4th.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What do we call the time when we sleep?', '["Night", "Morning", "Noon", "Afternoon"]', 0, 'Night is when most people sleep. Morning is when we wake up, noon is midday, afternoon is after noon.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'What is the opposite of early?', '["Late", "Soon", "Quick", "Fast"]', 0, 'Late is the opposite of early. Soon means in the near future, quick and fast relate to speed.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'How many months are in a year?', '["12", "6", "24", "10"]', 0, 'There are 12 months in one year: January through December. 6 is half a year, 24 is incorrect.', 'easy'),

('foundation', 'essential-vocabulary', 'beginner', 'What word means "every day"?', '["Daily", "Weekly", "Monthly", "Yearly"]', 0, 'Daily means happening every day. Weekly is every week, monthly is every month, yearly is every year.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you call a period of ten years?', '["Decade", "Century", "Millennium", "Year"]', 0, 'A decade is 10 years. A century is 100 years, a millennium is 1000 years.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What word means "happening twice a week"?', '["Biweekly", "Daily", "Weekly", "Monthly"]', 0, 'Biweekly can mean twice a week or every two weeks. Daily is every day, weekly is once a week.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What time expression means "right now"?', '["Currently", "Yesterday", "Tomorrow", "Later"]', 0, 'Currently means at this present moment. Yesterday is past, tomorrow is future, later is after now.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What word means "lasting forever"?', '["Eternal", "Temporary", "Brief", "Short"]', 0, 'Eternal means lasting forever or endless. Temporary, brief, and short all mean limited duration.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you call the day after today?', '["Tomorrow", "Yesterday", "Tonight", "Today"]', 0, 'Tomorrow is the day after today. Yesterday is the day before today, tonight is the evening of today.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What word means "at the same time"?', '["Simultaneously", "Separately", "Later", "Earlier"]', 0, 'Simultaneously means happening at exactly the same time. Separately means apart, later and earlier refer to different times.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What phrase means "in the end"?', '["Eventually", "Initially", "Originally", "Firstly"]', 0, 'Eventually means in the end or finally. Initially, originally, and firstly refer to the beginning.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What word means "happening often"?', '["Frequently", "Rarely", "Never", "Seldom"]', 0, 'Frequently means happening often or regularly. Rarely, never, and seldom mean not happening often.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What expression means "at this moment"?', '["Now", "Then", "Later", "Before"]', 0, 'Now means at this exact moment. Then refers to past or future, later is after now, before is earlier.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What word means "once in a while"?', '["Occasionally", "Always", "Never", "Constantly"]', 0, 'Occasionally means sometimes or once in a while. Always means every time, never means at no time, constantly means continuously.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'What do you call the middle of the night?', '["Midnight", "Noon", "Morning", "Evening"]', 0, 'Midnight is 12:00 AM, the middle of the night. Noon is midday, morning and evening are different times.', 'medium'),

('foundation', 'essential-vocabulary', 'beginner', 'What word means "happening every two years"?', '["Biennial", "Annual", "Biweekly", "Bimonthly"]', 0, 'Biennial means every two years. Annual is yearly, biweekly is twice a week, bimonthly is twice a month.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What expression means "from time to time"?', '["Periodically", "Continuously", "Perpetually", "Incessantly"]', 0, 'Periodically means happening at intervals or from time to time. Continuously, perpetually, and incessantly mean without stopping.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What word describes something that lasts a very short time?', '["Fleeting", "Permanent", "Lasting", "Enduring"]', 0, 'Fleeting means very brief or momentary. Permanent, lasting, and enduring all mean continuing for a long time.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What word means "existing from birth"?', '["Innate", "Acquired", "Learned", "Developed"]', 0, 'Innate means existing from birth or natural. Acquired, learned, and developed come after birth through experience.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What phrase means "before the usual time"?', '["Prematurely", "Belatedly", "Eventually", "Finally"]', 0, 'Prematurely means happening too early or before the proper time. Belatedly means late, eventually and finally mean in the end.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'What word means "happening without interruption"?', '["Continuously", "Intermittently", "Occasionally", "Sporadically"]', 0, 'Continuously means happening without breaks. Intermittently, occasionally, and sporadically all mean with breaks or irregularly.', 'hard'),

-- Subtopic 5: Places & Locations (30Q) - 12 easy, 12 medium, 6 hard
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to buy things?', '["Shop", "School", "Hospital", "Library"]', 0, 'We go to a shop (or store) to buy things. Schools are for education, hospitals for treatment, libraries for books.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do sick people go?', '["Hospital", "Market", "Cinema", "Restaurant"]', 0, 'Sick people go to hospitals for medical treatment. Markets sell goods, cinemas show films, restaurants serve food.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do children go to learn?', '["School", "Park", "Zoo", "Beach"]', 0, 'Children go to school to learn and study. Parks are for playing, zoos have animals, beaches are by the sea.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to watch movies?', '["Cinema", "Library", "Museum", "Temple"]', 0, 'We go to a cinema (or theater) to watch movies. Libraries have books, museums have exhibits, temples are for worship.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to borrow books?', '["Library", "Bakery", "Pharmacy", "Bank"]', 0, 'We go to a library to borrow books. Bakeries sell bread, pharmacies sell medicine, banks handle money.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to eat with family?', '["Restaurant", "Office", "Factory", "Station"]', 0, 'We go to restaurants to eat meals. Offices are for work, factories make products, stations are for travel.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to see animals?', '["Zoo", "Church", "Court", "Stadium"]', 0, 'We go to a zoo to see various animals. Churches are for worship, courts handle legal matters, stadiums host sports.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you keep your money?', '["Bank", "Garden", "Garage", "Basement"]', 0, 'We keep money in a bank for safety. Gardens grow plants, garages store cars, basements are underground rooms.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do trains stop?', '["Station", "Airport", "Harbor", "Terminal"]', 0, 'Trains stop at railway stations. Airports are for planes, harbors for ships, terminals can be for various transport.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to pray?', '["Temple", "Mall", "Gym", "Pool"]', 0, 'People go to temples (or churches, mosques) to pray. Malls are for shopping, gyms for exercise, pools for swimming.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do planes land?', '["Airport", "Station", "Port", "Depot"]', 0, 'Planes land at airports. Stations are for trains, ports for ships, depots are storage places.', 'easy'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to swim?', '["Pool", "Desert", "Mountain", "Forest"]', 0, 'We swim in pools (or at beaches). Deserts are dry areas, mountains are high land, forests have many trees.', 'easy'),

('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to buy medicine?', '["Pharmacy", "Butcher", "Florist", "Jeweler"]', 0, 'We buy medicine from a pharmacy (or chemist). Butchers sell meat, florists sell flowers, jewelers sell jewelry.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to send letters?', '["Post office", "Fire station", "Police station", "Embassy"]', 0, 'We send letters from a post office. Fire stations handle fires, police stations handle crime, embassies represent countries.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to see historical objects?', '["Museum", "Auditorium", "Laboratory", "Workshop"]', 0, 'We see historical objects in museums. Auditoriums host events, laboratories conduct experiments, workshops make things.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to exercise?', '["Gymnasium", "Cafeteria", "Dormitory", "Canteen"]', 0, 'We exercise in a gymnasium (or gym). Cafeterias and canteens serve food, dormitories are sleeping places.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do judges work?', '["Courthouse", "Warehouse", "Greenhouse", "Lighthouse"]', 0, 'Judges work in courthouses. Warehouses store goods, greenhouses grow plants, lighthouses guide ships.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to see live performances?', '["Theater", "Clinic", "Boutique", "Kiosk"]', 0, 'We see live performances in theaters. Clinics provide medical care, boutiques sell fashion, kiosks are small shops.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do university students study?', '["Campus", "Playground", "Courtyard", "Backyard"]', 0, 'University students study on a campus. Playgrounds are for children, courtyards are open spaces, backyards are behind houses.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to cut your hair?', '["Salon", "Laundry", "Dairy", "Bakery"]', 0, 'We get haircuts at a salon (or barber shop). Laundries clean clothes, dairies sell milk products, bakeries sell bread.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do scientists work?', '["Laboratory", "Cafeteria", "Lounge", "Corridor"]', 0, 'Scientists work in laboratories conducting experiments. Cafeterias serve food, lounges are relaxation areas, corridors are hallways.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go to watch sports?', '["Stadium", "Cathedral", "Monastery", "Sanctuary"]', 0, 'We watch sports in stadiums. Cathedrals, monasteries, and sanctuaries are religious or protected places.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do you go camping?', '["Campsite", "Arcade", "Lobby", "Hallway"]', 0, 'We camp at campsites (or in nature). Arcades have games, lobbies are entrance areas, hallways connect rooms.', 'medium'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do orphans live?', '["Orphanage", "Observatory", "Conservatory", "Refinery"]', 0, 'Orphans live in orphanages. Observatories study stars, conservatories are for music or plants, refineries process materials.', 'medium'),

('foundation', 'essential-vocabulary', 'beginner', 'Where do ambassadors work?', '["Embassy", "Foundry", "Tannery", "Brewery"]', 0, 'Ambassadors work in embassies representing their countries. Foundries melt metal, tanneries process leather, breweries make beer.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'Where are criminals kept?', '["Prison", "Sanctuary", "Pavilion", "Gazebo"]', 0, 'Criminals are kept in prisons (or jails). Sanctuaries are safe places, pavilions and gazebos are outdoor structures.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do astronomers work?', '["Observatory", "Infirmary", "Apiary", "Aviary"]', 0, 'Astronomers work in observatories to study stars and space. Infirmaries treat sick people, apiaries keep bees, aviaries keep birds.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'Where are dead people buried?', '["Cemetery", "Sanctuary", "Dormitory", "Nursery"]', 0, 'Dead people are buried in cemeteries (or graveyards). Sanctuaries are safe places, dormitories are for sleeping, nurseries are for children or plants.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'Where do monks live?', '["Monastery", "Armory", "Treasury", "Granary"]', 0, 'Monks live in monasteries for religious life. Armories store weapons, treasuries store valuables, granaries store grain.', 'hard'),
('foundation', 'essential-vocabulary', 'beginner', 'Where are historical documents kept?', '["Archive", "Depot", "Hangar", "Silo"]', 0, 'Historical documents are kept in archives. Depots store goods, hangars house aircraft, silos store grain.', 'hard');
